import {store} from './store.js';
const money=n=>new Intl.NumberFormat('en-US',{style:'currency',currency:'USD'}).format(Number(n)||0);const s=()=>store.get();
export const pages={
dashboard(){const x=s(),bills=x.bills.reduce((a,b)=>a+Number(b.amount||0),0),cash=Number(x.checking)+Number(x.savings),projected=cash-bills,progress=x.goals.length?Math.round(x.goals.reduce((a,g)=>a+Number(g.progress||0),0)/x.goals.length):0,journalCount=x.journalEntries.length,goalCount=x.goals.length;return `<div class="pagehead executive-head"><div><div class="eyebrow">Executive command center</div><h1>Good ${new Date().getHours()<12?'morning':new Date().getHours()<17?'afternoon':'evening'}, Keyona.</h1><p class="sub">Your whole life, beautifully summarized.</p></div><span class="pill">${new Date().toLocaleDateString('en-US',{weekday:'long',month:'long',day:'numeric'})}</span></div>
<section class="command-banner card luxe"><div><div class="eyebrow">Morning briefing</div><h2>Your day, beautifully arranged.</h2><p>Weather, calendar, money, family, wellness, learning, and progress—connected in one calm view.</p><div class="briefing-actions"><button class="btn" data-jump="calendar">Review today</button><button class="btn secondary" data-jump="journal">Open Reflection Garden</button></div></div><img src="profile.jpg" alt="Keyona"></section>
<div class="module-grid premium-modules">${[['calendar','🗓️','Agenda','Today + next 7 days'],['lani','💗','Lani','Memories + milestones'],['career','🎓','Academy','Payments mastery'],['business','🧠','Executive Intelligence','Memory + reminders'],['money','✉️','Financial Studio','Cash + bills'],['wellness','💧','Wellness Studio','Water + movement'],['journal','📖','Reflection Garden','Private reflection'],['goals','🏆','25 Hard','Annual challenge'],['progress','📊','Growth Studio','Wins + analytics'],['sanctuary','🏡','Sanctuary','Household rhythm'],['premium','🔑','Design + Data','Themes + vault'],['intelligence','✨','Morning Brief','Connected intelligence']].map(a=>`<button class="module" data-jump="${a[0]}"><span class="icon">${a[1]}</span><strong>${a[2]}</strong><small>${a[3]}</small></button>`).join('')}</div>
<section class="dashboard-section"><div class="section-title"><div><div class="eyebrow">Global awareness</div><h2>World clocks + weather</h2></div><span id="weatherStatus" class="pill">Updating automatically…</span></div><div id="weatherGrid" class="weather-grid"></div></section>
<section class="dashboard-section"><div class="section-title"><div><div class="eyebrow">Financial command</div><h2>Cash position</h2></div><button class="btn ghost" data-jump="money">Open Financial Studio</button></div><div class="finance-strip"><article class="card metric-card"><div class="mini">Available cash</div><div class="metric">${money(cash)}</div><p>Checking ${money(x.checking)} · Savings ${money(x.savings)}</p></article><article class="card metric-card"><div class="mini">Upcoming bills</div><div class="metric">${money(bills)}</div><p>${x.bills.length} scheduled bill${x.bills.length===1?'':'s'}</p></article><article class="card metric-card ${projected<0?'warning-card':''}"><div class="mini">Projected balance</div><div class="metric">${money(projected)}</div><p>After all currently listed bills</p></article></div></section>
<div class="dashboard-grid"><article class="card luxe dashboard-panel span-2"><div class="section-title"><h3>Today + Next 7 Days</h3><button class="btn ghost" data-jump="calendar">View Agenda</button></div><div id="dashboardAgenda"></div></article><article class="card luxe dashboard-panel"><div class="section-title"><h3>Lani Snapshot</h3><button class="btn ghost" data-jump="lani">Open corner</button></div><div id="dashboardLani"></div><div id="dashboardLaniCaption" class="snapshot-caption"></div></article><article class="card luxe dashboard-panel"><h3>Top Three</h3><div class="priority-list">${x.top3.map((t,i)=>`<label class="priority-card"><input data-top3="${i}" type="checkbox" ${x.top3Done[i]?'checked':''}><span><b>${t||'Choose priority '+(i+1)}</b><small>${x.top3Done[i]?'Complete':'Tap when complete'}</small></span></label>`).join('')}</div><button class="btn ghost" id="editTop3">Edit priorities</button></article><article class="card luxe dashboard-panel"><div class="mini">Wellness today</div><div class="metric-row"><span><b>${x.water}/8</b><small>Water</small></span><span><b>${x.gymMinutes}</b><small>Gym min</small></span></div><div class="bar"><span style="width:${Math.min(100,x.water/8*100)}%"></span></div><button class="btn ghost" data-jump="wellness">Open wellness</button></article><article class="card luxe dashboard-panel"><div class="mini">Growth snapshot</div><div class="metric-row"><span><b>${progress}%</b><small>25 Hard</small></span><span><b>${goalCount}</b><small>Goals</small></span><span><b>${journalCount}</b><small>Entries</small></span></div><button class="btn ghost" data-jump="progress">View progress</button></article><article class="card luxe dashboard-panel"><div class="mini">Payments Academy</div><h3>${x.careerNotes.length?'Continue your payments mastery':'Choose your next lesson'}</h3><p>${x.careerNotes.length?`${x.careerNotes.length} private case note${x.careerNotes.length===1?'':'s'} saved.`:'Authorization, settlement, pay-ins, pay-outs, risk, and reconciliation are ready.'}</p><button class="btn ghost" data-jump="career">Open Payments Academy</button></article><article class="card luxe dashboard-panel"><div class="mini">Executive Intelligence</div><h3>${Object.values(x.pulseCache?.categories||{}).flat().length?Object.values(x.pulseCache.categories).flat().length+' trusted stories ready':'Your memory desk awaits'}</h3><p>${x.pulseCache?.updatedAt?'American, English-language intelligence refreshed '+new Date(x.pulseCache.updatedAt).toLocaleDateString('en-US',{month:'short',day:'numeric'})+'.':'Open Intelligence to gather trusted U.S. headlines.'}</p><button class="btn ghost" data-jump="business">Open Intelligence</button></article></div>`},
intelligence(){const x=s(),today=new Date(),todayKey=today.toISOString().slice(0,10),next7=new Date(today);next7.setDate(today.getDate()+7);const events=Object.entries(x.calendar).filter(([d])=>d>=todayKey&&d<=next7.toISOString().slice(0,10)).sort(([a],[b])=>a.localeCompare(b));const unpaid=x.bills.filter(b=>!b.paid).sort((a,b)=>(a.due||'9999').localeCompare(b.due||'9999'));const goalProgress=x.goals.length?Math.round(x.goals.reduce((n,g)=>n+Number(g.progress||0),0)/x.goals.length):0;const done=x.top3Done.filter(Boolean).length;const pulse=Object.values(x.pulseCache?.categories||{}).flat().slice(0,4);const savings=x.savingsGoals.reduce((a,g)=>a+Number(g.current||0),0),savingsTarget=x.savingsGoals.reduce((a,g)=>a+Number(g.target||0),0);const insights=[];if(unpaid[0])insights.push({icon:'💳',title:'Next financial commitment',text:`${unpaid[0].name} · ${money(unpaid[0].amount)}${unpaid[0].due?` due ${new Date(unpaid[0].due+'T12:00:00').toLocaleDateString('en-US',{month:'short',day:'numeric'})}`:''}`});if(x.water<4)insights.push({icon:'💧',title:'Wellness nudge',text:`Water is at ${x.water}/8. One glass now keeps the goal easy later.`});if(goalProgress>0)insights.push({icon:'🏆',title:'Goal momentum',text:`Your 25 Hard goals average ${goalProgress}% complete.`});if(!insights.length)insights.push({icon:'✦',title:'Clear runway',text:'Your system is clear. Choose the next intentional move.'});return `<div class="pagehead intelligence-head"><div><div class="eyebrow">Connected intelligence</div><h1>Morning Brief</h1><p class="sub">One calm view of what deserves your attention today.</p></div><span class="pill">${today.toLocaleDateString('en-US',{weekday:'long',month:'long',day:'numeric'})}</span></div><section class="card brief-hero"><div><div class="eyebrow">Today at a glance</div><h2>${done}/3 priorities complete</h2><p>${events.length} agenda item${events.length===1?'':'s'} in the next seven days · ${unpaid.length} unpaid bill${unpaid.length===1?'':'s'} listed.</p></div><div class="brief-score" style="--score:${Math.round((done/3)*100)}%"><strong>${Math.round((done/3)*100)}%</strong><span>Top Three</span></div></section><div class="brief-metric-grid"><article class="card"><div class="mini">Water</div><div class="metric">${x.water}/8</div><div class="bar"><span style="width:${Math.min(100,x.water/8*100)}%"></span></div></article><article class="card"><div class="mini">Movement</div><div class="metric">${x.gymMinutes} min</div><p class="muted">Today’s logged activity</p></article><article class="card"><div class="mini">Savings goals</div><div class="metric">${savingsTarget?Math.round(savings/savingsTarget*100):0}%</div><p class="muted">${money(savings)} of ${money(savingsTarget)}</p></article><article class="card"><div class="mini">25 Hard</div><div class="metric">${goalProgress}%</div><p class="muted">Average goal completion</p></article></div><div class="intelligence-grid"><article class="card"><div class="section-title"><h3>Top Three</h3><button class="btn ghost" data-jump="dashboard">Edit</button></div>${x.top3.map((t,i)=>`<div class="brief-line ${x.top3Done[i]?'done':''}"><span>${x.top3Done[i]?'✓':'○'}</span><b>${t||`Priority ${i+1} not chosen`}</b></div>`).join('')}</article><article class="card"><div class="section-title"><h3>Agenda</h3><button class="btn ghost" data-jump="calendar">Open</button></div>${events.length?events.slice(0,6).map(([d,v])=>`<div class="brief-line"><span>📅</span><div><b>${v.subject||'Planned day'}</b><small>${new Date(d+'T12:00:00').toLocaleDateString('en-US',{weekday:'short',month:'short',day:'numeric'})}</small></div></div>`).join(''):'<div class="status">Nothing scheduled in the next seven days.</div>'}</article><article class="card"><h3>Smart Signals</h3>${insights.map(v=>`<div class="insight"><span>${v.icon}</span><div><b>${v.title}</b><p>${v.text}</p></div></div>`).join('')}</article><article class="card"><div class="section-title"><h3>Memory Highlights</h3><button class="btn ghost" data-jump="business">Open Intelligence</button></div>${pulse.length?pulse.map(v=>`<div class="brief-line"><span>📰</span><div><b>${v.title}</b><small>${v.source||'News source'}</small></div></div>`).join(''):'<div class="status">Capture a reminder or voice memo in Executive Intelligence.</div>'}</article><article class="card"><h3>Weekly Review</h3><textarea id="weeklyReviewText" rows="7" placeholder="What worked? What needs to roll forward? What deserves celebration?"></textarea><button id="saveWeeklyReview" class="btn">Save Weekly Review</button><div id="weeklyReviewList" class="review-list"></div></article><article class="card"><h3>Financial Watch</h3>${unpaid.length?unpaid.slice(0,5).map(v=>`<div class="brief-line"><span>💳</span><div><b>${v.name}</b><small>${money(v.amount)} · ${v.due||'No due date'}</small></div></div>`).join(''):'<div class="status">No unpaid bills are listed.</div>'}</article></div><article class="card global-search-card"><div class="section-title"><div><div class="eyebrow">Across your OS</div><h3>Global Search</h3></div><span class="pill">Private on this device</span></div><input id="globalSearch" class="input" type="search" placeholder="Search journal, agenda, goals, bills, memories, and academy notes…"><div id="globalSearchResults" class="search-results"><div class="status">Start typing to search the information saved in your OS.</div></div></article>`},
calendar(){return `<div class="pagehead"><div><div class="eyebrow">Connected daily planner</div><h1>Agenda</h1><p class="sub">Events, tasks, birthdays, holidays, and bills—visible at a glance.</p></div><div class="row"><button class="btn ghost" id="prevMonth">←</button><span id="monthLabel" class="pill"></span><button class="btn ghost" id="nextMonth">→</button></div></div><article class="card"><div class="calendar-legend"><span><i class="dot event"></i>Event</span><span><i class="dot task"></i>Task</span><span><i class="dot birthday"></i>Birthday</span><span><i class="dot holiday"></i>Holiday</span><span><i class="dot bill"></i>Bill</span></div><div id="calendarGrid" class="calendar"></div></article><div class="grid g2" style="margin-top:14px"><article class="card"><h3>Selected Day</h3><div id="selectedDayDetail" class="status">Tap a date to see everything scheduled.</div></article><article class="card"><h3>Next 7 Days</h3><div id="next7"></div></article></div><article class="card" style="margin-top:14px"><div class="section-title"><h3>Add or Edit Day</h3><span class="pill">One date · many layers</span></div><input id="calDate" class="input" type="date"><div class="agenda-tabs"><button class="btn ghost active" data-agenda-tab="event">Event</button><button class="btn ghost" data-agenda-tab="task">Task</button><button class="btn ghost" data-agenda-tab="birthday">Birthday</button><button class="btn ghost" data-agenda-tab="holiday">Holiday</button></div><input id="calSubject" class="input" placeholder="Day headline"><textarea id="calEvents" rows="3" placeholder="Events, one per line"></textarea><textarea id="calTasks" rows="3" placeholder="Tasks, one per line"></textarea><textarea id="calBirthdays" rows="2" placeholder="Birthdays, one per line"></textarea><textarea id="calHolidays" rows="2" placeholder="Holidays or observances"></textarea><textarea id="calNotes" rows="3" placeholder="Notes"></textarea><div class="row wrap"><button id="saveCalendarDay" class="btn">Save day</button><label class="btn secondary">Import .ics<input id="icsImport" hidden type="file" accept=".ics,text/calendar"></label><button id="icsExport" class="btn ghost">Export calendar</button></div><p class="muted">Google and Apple calendar files can be imported here. Live two-way sync requires OAuth and a secure backend, which GitHub Pages alone cannot provide.</p></article>`},
lani(){const f=s().laniFacts;return `<div class="lani-page"><div class="lani-sky" aria-hidden="true"><span>☀️</span><span>🦋</span><span>🌈</span><span>🌸</span></div><div class="pagehead lani-head"><div><div class="eyebrow">Her joyful little world</div><h1>Lani’s Corner</h1><p class="sub">A living memory book for favorites, milestones, practical details, and growing-up magic.</p></div><span class="lani-stickers">🧸 🎀 ⭐</span></div>
<section class="lani-hero card"><div><div class="eyebrow">Little love, big personality</div><h2 id="laniHeroName">Lani at a glance</h2><p id="laniHeroLine">Add her favorites and newest memory to bring this page to life.</p><div class="lani-quick-facts"><button class="pill editable-pill" data-quick-lani="age" id="laniAgePill">Age —</button><button class="pill editable-pill" data-quick-lani="height" id="laniHeightPill">Height —</button><button class="pill editable-pill" data-quick-lani="favoriteColor" id="laniColorPill">Favorite color —</button></div><p class="muted">Tap a quick detail to update it instantly.</p></div><div class="lani-orbit"><span>🌷</span><span>🫧</span><span>🦄</span></div></section>
<div class="grid g2 lani-main-grid"><article class="card lani-collage-card"><div class="section-title"><div><div class="eyebrow">Memories in motion</div><h3>Living Photo Collage</h3></div><span class="pill" id="photoCount">0 photos</span></div><div id="laniSlideshow" class="slideshow"></div><div class="slideshow-controls"><button id="laniPrev" class="btn ghost" aria-label="Previous photo">←</button><div id="laniDots" class="slide-dots"></div><button id="laniNext" class="btn ghost" aria-label="Next photo">→</button></div><div id="laniThumbs" class="lani-thumbs"></div><label class="btn lani-upload">Add Photos<input id="laniUpload" hidden type="file" multiple accept="image/*"></label><div id="laniUploadStatus" class="status">Photos are stored in the device photo vault for reliable persistence.</div><label>Featured dashboard caption<textarea id="laniFeaturedCaption" rows="2" placeholder="Tiny shoes. Major main-character energy."></textarea></label><button id="saveLaniCaption" class="btn secondary">Save dashboard caption</button><p class="muted photo-note">Up to 18 photos are stored in IndexedDB, designed for larger local files.</p></article>
<article class="card"><div class="section-title"><div><div class="eyebrow">Easy to update</div><h3>Fun Facts + Gift Guide</h3></div><button id="printLani" class="btn ghost">Share Snapshot</button></div><div class="funfacts">${[['birthday','Birthday'],['age','Age'],['height','Height'],['favoriteColor','Favorite Color'],['foods','Top Foods'],['toys','Favorite Toys'],['shows','Favorite Shows'],['activities','Favorite Activities'],['clothingSize','Clothing Size'],['shoeSize','Shoe Size'],['giftIdeas','Gift Ideas / Wishlist']].map(([k,l])=>`<label>${l}<textarea data-lani-fact="${k}" rows="2">${f[k]||''}</textarea></label>`).join('')}</div><details class="sensitive-details"><summary>Private care details</summary><p class="muted">These details stay out of the birthday snapshot.</p><label>Medications<textarea data-lani-fact="medications" rows="2">${f.medications||''}</textarea></label><label>Allergies<textarea data-lani-fact="allergies" rows="2">${f.allergies||''}</textarea></label></details></article></div>
<div class="grid g2 lani-secondary-grid"><article class="card"><div class="eyebrow">Growing-up story</div><h3>Memory Timeline</h3><input id="memoryTitle" class="input" placeholder="Memory title"><textarea id="memoryText" rows="4" placeholder="What happened? What made it special?"></textarea><button id="saveMemory" class="btn">Save Memory</button><div id="memoryList" class="memory-timeline"></div></article><article class="card snapshot-card" id="laniShareCard"><div class="eyebrow">Birthday-ready</div><h3>Lani’s Favorites Snapshot</h3><p>A clean, screenshot-friendly guide for family and friends.</p><div id="giftSnapshot"></div></article></div>
<div class="grid g2 lani-checklists"><article class="card"><div class="eyebrow">Pool day</div><h3>Swim Checklist</h3><div id="swimChecklist" class="check-grid"></div></article><article class="card"><div class="eyebrow">Ready for the week</div><h3>Weekly Prep</h3><div id="laniPrepChecklist" class="check-grid"></div></article></div></div>`},
career(){return `<div class="pagehead"><div><div class="eyebrow">Payments mastery</div><h1>Payments Academy</h1><p class="sub">Learning and reference only—current news stays inside Pulse.</p></div></div><div class="grid g3"><article class="card"><h3>Payments Academy</h3><div class="stack">${['Authorization & Capture','Settlement & Reconciliation','Pay-Ins','Pay-Outs','Chargebacks','ACH & RTP','Fraud & Risk'].map(x=>`<button class="btn ghost lesson" data-lesson="${x}">${x}</button>`).join('')}</div></article><article class="card"><h3>Regulations & Standards</h3><a class="entry" target="_blank" href="https://www.consumerfinance.gov/compliance/" rel="noopener noreferrer">CFPB Compliance</a><a class="entry" target="_blank" href="https://www.fincen.gov/resources/statutes-regulations" rel="noopener noreferrer">FinCEN Regulations</a><a class="entry" target="_blank" href="https://www.pcisecuritystandards.org/" rel="noopener noreferrer">PCI Security Standards</a><a class="entry" target="_blank" href="https://www.federalreserve.gov/paymentsystems.htm" rel="noopener noreferrer">Federal Reserve Payment Systems</a><p class="muted">Official sources; review dates and applicability before relying on a rule.</p></article><article class="card"><h3>Private Case Journal</h3><textarea id="careerNote" rows="8" placeholder="Case, investigation, outcome, lesson…"></textarea><button id="saveCareerNote" class="btn">Save Note</button><div id="careerNoteList"></div></article></div><article class="card" style="margin-top:14px"><h3 id="lessonTitle">Choose a lesson</h3><div id="lessonBody" class="prompt">Select a concept to begin.</div></article><section class="card academy-expansion"><div class="section-title"><div><div class="eyebrow">Build your path</div><h3>Payments Learning Studio</h3></div><span class="pill">Personal playbook</span></div><div class="academy-track-grid"><article><h4>Core rails</h4><p>Cards, ACH, RTP, FedNow, wires, wallets, and alternative payments.</p></article><article><h4>Risk + compliance</h4><p>KYC, AML, sanctions, PCI DSS, disputes, fraud, and controls.</p></article><article><h4>Operations</h4><p>Settlement, reconciliation, exceptions, returns, SLAs, and incident response.</p></article><article><h4>Customer success</h4><p>Discovery, onboarding, executive communication, troubleshooting, and renewal value.</p></article></div><label>My next learning objective<input id="academyObjective" class="input" placeholder="Example: Master settlement exceptions"></label><button id="saveAcademyObjective" class="btn">Save learning objective</button><div class="resource-library"><a target="_blank" rel="noopener" href="https://www.frbservices.org/financial-services/fednow">Federal Reserve FedNow</a><a target="_blank" rel="noopener" href="https://www.nacha.org/rules">Nacha Rules</a><a target="_blank" rel="noopener" href="https://www.fincen.gov/resources/statutes-regulations">FinCEN</a><a target="_blank" rel="noopener" href="https://www.consumerfinance.gov/compliance/">CFPB Compliance</a><a target="_blank" rel="noopener" href="https://www.pcisecuritystandards.org/">PCI SSC</a><a target="_blank" rel="noopener" href="https://www.federalreserve.gov/paymentsystems.htm">Federal Reserve Payment Systems</a></div></section>`},
business(){const x=s(),cached=x.pulseCache||{},topics=x.pulsePreferences?.topics||['Business','Payments','Fintech','AI','Arizona','U.S.','World'];return `<div class="pagehead pulse-head"><div><div class="eyebrow">Connected intelligence</div><h1>Pulse</h1><p class="sub">A calm executive briefing across business, payments, AI, Arizona, the U.S., and the world.</p></div><div class="pulse-actions"><span id="pulseUpdated" class="pill">${cached.updatedAt?`Updated ${new Date(cached.updatedAt).toLocaleString()}`:'Ready to refresh'}</span><button id="refreshPulse" class="btn">Refresh briefing</button></div></div><section id="pulseHero" class="card pulse-hero"><div><div class="eyebrow">Executive summary</div><h2 id="pulseHeroTitle">Your intelligence desk is ready.</h2><p id="pulseHeroText">Refresh to gather the latest headlines. Your most recent successful briefing remains available offline.</p></div><div id="pulseState" class="pulse-state"><span class="pulse-orb"></span><b>Standing by</b><small>Live public feed · secure endpoint ready</small></div></section><div id="pulseSummary" class="pulse-summary"></div><div id="pulseTopics" class="pulse-topic-grid">${topics.map(t=>`<article class="card pulse-topic" data-pulse-topic="${t}"><div class="section-title"><div><div class="mini">Intelligence channel</div><h3>${t}</h3></div><span class="pill">Waiting</span></div><div class="pulse-skeleton">${'<i></i>'.repeat(3)}</div></article>`).join('')}</div><article class="card pulse-connection"><div><div class="eyebrow">Architecture</div><h3>Secure by design</h3><p>Pulse uses a public no-key source by default and automatically prefers the serverless endpoint configured in <code>config.js</code>. No private API key belongs in GitHub Pages.</p></div><span class="pill">Cached offline</span></article>`},
money(){const x=s(),billTotal=x.bills.reduce((a,v)=>a+Number(v.amount||0),0),cash=Number(x.checking)+Number(x.savings)+Number(x.otherAssets||0),projected=cash-billTotal,netWorth=cash-Number(x.debts||0),monthlyIncome=Number(x.monthlyIncome||0),surplus=monthlyIncome-billTotal;return `<div class="money-page"><div class="pagehead money-head"><div><div class="eyebrow">Private financial studio</div><h1>Financial Studio</h1><p class="sub">Cash flow, bills, savings, sinking funds, and net worth—beautifully connected.</p></div><span class="money-ornament premium-glyph" aria-hidden="true">◈ ◇ ⟡</span></div>
<section class="money-hero card"><div><div class="eyebrow">Financial clarity</div><h2>${projected>=0?'Your money has a plan.':'Let’s close the gap.'}</h2><p>See what you have, what is leaving, and what remains—without hunting through separate screens.</p></div><div class="net-worth-orb"><span>Net worth</span><strong>${money(netWorth)}</strong></div></section>
<div class="finance-strip money-metrics"><article class="card metric-card"><div class="mini">Available cash</div><div class="metric" id="moneyAvailable">${money(cash)}</div><p>Checking + savings + other assets</p></article><article class="card metric-card"><div class="mini">Upcoming bills</div><div class="metric" id="moneyBillsTotal">${money(billTotal)}</div><p>${x.bills.length} listed obligation${x.bills.length===1?'':'s'}</p></article><article class="card metric-card ${projected<0?'warning-card':''}"><div class="mini">Projected balance</div><div class="metric" id="moneyProjected">${money(projected)}</div><p>After currently listed bills</p></article><article class="card metric-card ${surplus<0?'warning-card':''}"><div class="mini">Monthly surplus</div><div class="metric" id="moneySurplus">${money(surplus)}</div><p>Income less listed bills</p></article></div>
<div class="grid g2 money-primary-grid"><article class="card account-card"><div class="section-title"><div><div class="eyebrow">Your balances</div><h3>Cash Position</h3></div><span class="pill">Private on this device</span></div><div class="money-form-grid"><label>Checking<input id="checking" class="input" type="number" step="0.01" value="${x.checking}"></label><label>Savings<input id="savings" class="input" type="number" step="0.01" value="${x.savings}"></label><label>Other assets<input id="otherAssets" class="input" type="number" step="0.01" value="${x.otherAssets||0}"></label><label>Total debts<input id="debts" class="input" type="number" step="0.01" value="${x.debts||0}"></label><label>Monthly income<input id="monthlyIncome" class="input" type="number" step="0.01" value="${x.monthlyIncome||0}"></label></div><button id="saveAccounts" class="btn">Save Financial Snapshot</button></article>
<article class="card cashflow-card"><div class="section-title"><div><div class="eyebrow">This month</div><h3>Cash-Flow Outlook</h3></div><span class="pill" id="cashflowStatus">${surplus>=0?'Surplus':'Deficit'}</span></div><canvas id="cashflowCanvas" height="250" aria-label="Monthly income and bills chart"></canvas><div class="cashflow-legend"><span><i class="legend-income"></i>Income ${money(monthlyIncome)}</span><span><i class="legend-bills"></i>Bills ${money(billTotal)}</span><span><i class="legend-left"></i>Remaining ${money(surplus)}</span></div></article></div>
<div class="grid g2 money-secondary-grid"><article class="card bill-manager"><div class="section-title"><div><div class="eyebrow">Never miss the details</div><h3>Bill Manager</h3></div><span class="pill" id="billCount">${x.bills.length} bills</span></div><input id="billEditId" type="hidden"><div class="money-form-grid"><label>Bill name<input id="billName" class="input" placeholder="Rent, internet, insurance…"></label><label>Amount<input id="billAmount" class="input" type="number" step="0.01" placeholder="0.00"></label><label>Due date<input id="billDue" class="input" type="date"></label><label>Category<select id="billCategory"><option>Housing</option><option>Utilities</option><option>Transportation</option><option>Insurance</option><option>Subscriptions</option><option>Family</option><option>Debt</option><option>Other</option></select></label><label>Frequency<select id="billFrequency"><option>Monthly</option><option>Weekly</option><option>Biweekly</option><option>Quarterly</option><option>Annual</option><option>One-time</option></select></label><label class="toggle-label"><input id="billPaid" type="checkbox"> Mark paid</label></div><div class="row wrap"><button id="addBill" class="btn">Save Bill</button><button id="cancelBillEdit" class="btn ghost" type="button">Clear</button></div><div id="billList" class="bill-list"></div></article>
<article class="card"><div class="section-title"><div><div class="eyebrow">Build the life ahead</div><h3>Savings Goals</h3></div><span class="pill">Milestones celebrate</span></div><div class="money-form-grid"><label>Goal name<input id="saveGoalName" class="input" placeholder="Emergency fund, vacation…"></label><label>Target<input id="saveGoalTarget" class="input" type="number" step="0.01" placeholder="0.00"></label><label>Current amount<input id="saveGoalCurrent" class="input" type="number" step="0.01" placeholder="0.00"></label><label>Target date<input id="saveGoalDate" class="input" type="date"></label></div><button id="addSavingGoal" class="btn">Create Goal</button><div id="savingGoalList" class="saving-goal-list"></div></article></div>
<div class="grid g2 money-tertiary-grid"><article class="card"><div class="section-title"><div><div class="eyebrow">Planned expenses</div><h3>Sinking Funds</h3></div><span class="pill">Spend without surprise</span></div><div class="money-form-grid"><label>Fund name<input id="fundName" class="input" placeholder="Birthdays, car care…"></label><label>Target<input id="fundTarget" class="input" type="number" step="0.01" placeholder="0.00"></label><label>Saved<input id="fundCurrent" class="input" type="number" step="0.01" placeholder="0.00"></label></div><button id="addSinkingFund" class="btn">Add Sinking Fund</button><div id="sinkingFundList" class="saving-goal-list"></div></article><article class="card"><div class="eyebrow">Your financial pulse</div><h3>Money Insights</h3><div id="moneyInsights" class="insight-stack"></div></article></div><section id="billControlMount6B19" class="bill-control-mount-6b19" aria-label="Full bill list"></section></div>`},
wellness(){const x=s();return `<div class="pagehead"><div><div class="eyebrow">Strong, nourished, consistent</div><h1>Wellness Studio</h1><p class="sub">Progress without perfection theater.</p></div></div><div class="grid g4"><article class="card gradient-card"><h3>Water</h3><div class="metric">${x.water}/8</div><button id="waterPlus" class="btn">＋ Glass</button><button id="waterReset" class="btn ghost">Reset</button></article><article class="card gradient-card"><h3>Gym</h3><div class="metric">${x.gymMinutes} min</div><input id="gymMinutes" class="input" type="number" value="${x.gymMinutes}"><button id="saveGym" class="btn">Save</button></article><article class="card gradient-card"><h3>Body Goals</h3><p>Glute growth, back strength, posture, sustainable fat loss, and recovery.</p></article><article class="card gradient-card"><h3>Shortcuts</h3><a class="btn" href="myfitnesspal://">MyFitnessPal</a> <a class="btn secondary" target="_blank" href="https://www.eosfitness.com/">EOS</a></article></div><div class="grid g2" style="margin-top:14px"><article class="card"><h3>Achievement Cabinet</h3><div class="row"><span class="pill">${x.water>=8?'🏆 Hydrated':'🔑 First Step'}</span><span class="pill">${x.gymMinutes>=30?'🏆 Workout':'✨ Keep Going'}</span></div></article><article class="card"><h3>Today’s Insight</h3><div class="prompt">Consistency beats intensity you cannot repeat. Annoying advice, but annoyingly undefeated.</div></article></div>`},
sanctuary(){return `<div class="pagehead"><div><div class="eyebrow">Household rhythm</div><h1>Sanctuary</h1><p class="sub">The former Home tab—same purpose, clearer destination.</p></div></div><div class="grid g3"><article class="card"><h3>Daily Reset</h3>${['Kitchen reset','Living room reset','Laundry check','Prepare tomorrow','Ten-minute tidy'].map(x=>`<label class="entry"><input type="checkbox"> ${x}</label>`).join('')}</article><article class="card"><h3>Recurring Routines</h3><p>Guided launch sequences work inside the OS. Direct Alexa routine execution requires an Alexa Skill or supported deep-link workflow.</p><button class="btn">Morning Launch</button><button class="btn secondary">Evening Reset</button></article><article class="card"><h3>Alexa Connection</h3><div class="status">Integration-ready; not enabled until an Alexa Skill/account connection exists.</div></article></div>`},
journal(){return `<div class="pagehead"><div><div class="eyebrow">The Reflection Garden</div><h1>Reflection Garden</h1><p class="sub">Guided prompts, fresh perspective, and an archive organized by the themes of your life.</p></div><span style="font-size:42px">❧ 🌸 ❧</span></div><div class="grid g2"><article class="card"><div class="row"><h3 id="promptCategory">Self-Love</h3><button id="micButton" class="btn ghost">🎙️ Speak</button></div><div id="journalPrompt" class="prompt"></div><div class="row wrap"><button id="previousPrompt" class="btn ghost">← Previous</button><button id="nextPrompt" class="btn ghost">New prompt →</button></div><textarea id="journalText" rows="12" placeholder="Write or speak what feels true today…"></textarea><button id="saveJournal" class="btn">Save Entry</button></article><article class="card"><h3>Prompt Categories</h3><div class="prompt-chip-grid">${['Self-Love','Growth','Gratitude','Motherhood','Career','Mindset','Reflection','Dreams','Hopeful','Tender'].map(x=>`<button class="btn ghost prompt-category" data-category="${x}">${x}</button>`).join('')}</div><h3 style="margin-top:18px">Archive by Theme</h3><div id="journalArchiveFilters" class="prompt-chip-grid"></div><div id="journalTimeline"></div></article></div>`},
goals(){return `<div class="pagehead"><div><div class="eyebrow">Your annual challenge</div><h1>25 Hard</h1><p class="sub">Twenty-five meaningful goals with milestones and celebration.</p></div></div><article class="card"><div class="row"><input id="goalName" class="input" placeholder="Add a goal"><select id="goalCategory"><option>Life</option><option>Money</option><option>Career</option><option>Wellness</option><option>Family</option><option>Business</option></select><button id="addGoal" class="btn">Add</button></div></article><div id="goalBoard" class="goal-board compact-goals" style="margin-top:14px"></div>`},
progress(){const x=s(),goalPct=x.goals.length?Math.round(x.goals.reduce((a,g)=>a+Number(g.progress||0),0)/x.goals.length):0,well=Math.min(100,Math.round(x.water/8*55+Math.min(x.gymMinutes,60)/60*45)),moneyPct=Math.max(0,Math.min(100,Math.round((Number(x.checking)+Number(x.savings)-x.bills.reduce((a,b)=>a+Number(b.amount||0),0))/Math.max(1,Number(x.checking)+Number(x.savings))*100))),journalPct=Math.min(100,x.journalEntries.length*5),completed=x.goals.filter(g=>Number(g.progress)>=100).length,totalWins=x.wins.length+x.savingsGoals.filter(g=>Number(g.current)>=Number(g.target)&&Number(g.target)>0).length;return `<div class="pagehead"><div><div class="eyebrow">Premium analytics</div><h1>Growth Studio</h1><p class="sub">Your momentum, milestones, and evidence of progress—made visible.</p></div><span class="pill">${totalWins} recorded win${totalWins===1?'':'s'}</span></div><div id="progressCards" class="growth-rings"><article class="card growth-ring-card"><div class="growth-ring" style="--p:${goalPct}"><span>${goalPct}%</span></div><h3>25 Hard</h3><p>${completed} completed goal${completed===1?'':'s'}</p></article><article class="card growth-ring-card"><div class="growth-ring" style="--p:${well}"><span>${well}%</span></div><h3>Wellness</h3><p>${x.water}/8 water · ${x.gymMinutes} min</p></article><article class="card growth-ring-card"><div class="growth-ring" style="--p:${moneyPct}"><span>${moneyPct}%</span></div><h3>Financial</h3><p>Cash after listed bills</p></article><article class="card growth-ring-card"><div class="growth-ring" style="--p:${journalPct}"><span>${journalPct}%</span></div><h3>Reflection</h3><p>${x.journalEntries.length} journal entries</p></article></div><div class="grid g2" style="margin-top:14px"><article class="card"><div class="section-title"><h3>Category Progress</h3><span class="pill">Connected metrics</span></div><canvas id="progressCanvas" height="260"></canvas></article><article class="card"><div class="section-title"><h3>Recent Wins</h3><span class="pill">Celebration cabinet</span></div><div id="wins"></div></article><article class="card"><h3>Milestone Timeline</h3><div id="milestoneTimeline"></div></article><article class="card"><h3>Activity Heat Map</h3><div id="activityHeatmap" class="heatmap"></div><p class="muted">A simple 28-day view based on saved activity across your OS.</p></article></div>`},
premium(){const x=s(),check=store.validate(),themes=[['champagne','✨','Champagne Luxe','Warm ivory, champagne gold, espresso ink'],['ivory','🤍','Royal Ivory','Crisp editorial neutrals and quiet gold'],['midnight','🌙','Midnight Noir','Charcoal blue, warm ivory, luminous gold'],['espresso','☕','Espresso Reserve','Walnut depth, cream type, bronze glow'],['obsidian','🖤','Obsidian Gold','True luxury black with restrained gold'],['sage','🌿','Botanical Sage','Soft garden greens and warm linen'],['rose','🌸','Rose Quartz','Blush surfaces with chocolate typography'],['ocean','🌊','Ocean Glass','Frosted blue-green with deep navy ink'],['lavender','🪻','Lavender Mist','Powdered violet and editorial plum'],['autumn','🍂','Autumn Manor','Tobacco, terracotta, and burnished gold'],['sapphire','💎','Sapphire Night','Deep blue jewel tones and warm gold'],['desert','🌅','Desert Bloom','Sun-washed clay, ivory, and sage']];return `<div class="pagehead design-head"><div><div class="eyebrow">Your private atelier</div><h1>Design + Data</h1><p class="sub">Shape the mood of your OS without sacrificing readability.</p></div><span class="pill">${themes.find(t=>t[0]===x.theme)?.[2]||'Champagne Luxe'}</span></div><section class="card design-hero"><div><div class="eyebrow">Design Studio 2.0</div><h2>Twelve complete visual identities.</h2><p>Every palette includes coordinated surfaces, text, controls, borders, shadows, and accessible contrast.</p></div><div class="design-swatch" aria-hidden="true"><i></i><i></i><i></i><i></i></div></section><section class="studio-section"><div class="section-title"><div><div class="eyebrow">Theme gallery</div><h2>Choose the atmosphere</h2></div><span class="pill">Tap to apply instantly</span></div><div class="theme-gallery">${themes.map(t=>`<button class="theme-card ${x.theme===t[0]?'selected':''}" data-theme-choice="${t[0]}"><div class="theme-preview theme-${t[0]}"><span></span><b></b><i></i></div><div class="theme-copy"><span>${t[1]}</span><div><strong>${t[2]}</strong><small>${t[3]}</small></div></div>${x.theme===t[0]?'<em>Applied</em>':''}</button>`).join('')}</div></section><div class="studio-grid"><article class="card"><div class="eyebrow">Personalization</div><h3>Finishing details</h3><label>Motion level<select id="motionSelect"><option value="standard" ${x.design.motion==='standard'?'selected':''}>Premium</option><option value="reduced" ${x.design.motion==='reduced'?'selected':''}>Reduced</option></select></label><label>Card treatment<select id="cardSelect"><option value="glass" ${x.design.cards==='glass'?'selected':''}>Frosted glass</option><option value="solid" ${x.design.cards==='solid'?'selected':''}>Solid editorial</option><option value="soft" ${x.design.cards==='soft'?'selected':''}>Soft elevation</option></select></label><label>Corner profile<select id="radiusSelect"><option value="classic" ${x.design.radius==='classic'?'selected':''}>Classic</option><option value="soft" ${x.design.radius==='soft'?'selected':''}>Soft</option><option value="ultra" ${x.design.radius==='ultra'?'selected':''}>Ultra soft</option></select></label><label>Background texture<select id="textureSelect"><option value="clean" ${x.design.texture==='clean'?'selected':''}>Clean</option><option value="linen" ${x.design.texture==='linen'?'selected':''}>Linen</option><option value="glow" ${x.design.texture==='glow'?'selected':''}>Ambient glow</option></select></label><label>Typography<select id="typeSelect"><option value="classic" ${x.design.type==='classic'?'selected':''}>Classic serif</option><option value="editorial" ${x.design.type==='editorial'?'selected':''}>Editorial</option><option value="modern" ${x.design.type==='modern'?'selected':''}>Modern</option></select></label></article><article class="card readability-card"><div class="eyebrow">Readability standard</div><h3>Luxury should never whisper too softly.</h3><div class="contrast-demo"><h4>Readable at every size</h4><p>Primary and secondary text remain distinct on every surface, in every theme.</p><button class="btn">Primary action</button><button class="btn secondary">Secondary</button></div><ul class="quality-list"><li>Strong body-text contrast</li><li>Visible focus states</li><li>Theme-aware charts and controls</li><li>Warm, readable dark palettes</li></ul></article><article class="card"><h3>Data Vault</h3><button id="exportData" class="btn">Export Verified Backup</button><label class="btn secondary">Import Backup<input id="importData" hidden type="file" accept=".json"></label><button id="recoverData" class="btn ghost">Restore Previous Save</button><p class="muted">A recovery copy is created before each successful save.</p></article><article class="card"><h3>Data Health</h3><div class="integrity-badge ${check.ok?'healthy':'warning'}">${check.ok?'✓ Healthy':'⚠ Review needed'}</div><p>${check.ok?'Your local data passed structural validation.':check.issues.join('<br>')}</p><small>Last saved: ${check.lastSaved?new Date(check.lastSaved).toLocaleString():'No saved update yet'}</small><button id="downloadDiagnostic" class="btn ghost">Download Diagnostic</button></article></div>`},
profile(){const x=s(),p=x.profile||{},goalPct=x.goals.length?Math.round(x.goals.reduce((a,g)=>a+Number(g.progress||0),0)/x.goals.length):0,well=Math.min(100,Math.round(x.water/8*55+Math.min(x.gymMinutes,60)/60*45)),savings=x.savingsGoals.reduce((a,g)=>a+Number(g.current||0),0),target=x.savingsGoals.reduce((a,g)=>a+Number(g.target||0),0),financial=target?Math.min(100,Math.round(savings/target*100)):0,life=Math.round((goalPct+well+financial+Math.min(100,x.journalEntries.length*5))/4),wins=x.wins.length+x.goals.filter(g=>Number(g.progress)>=100).length;return `<div class="pagehead profile-head"><div><div class="eyebrow">Private executive suite</div><h1>My Profile</h1><p class="sub">Identity, direction, goals, and the evidence of who you are becoming.</p></div><button class="btn ghost" data-jump="premium">Open Design Studio</button></div><section class="founder-card card"><img src="profile.jpg" alt="Founder portrait"><div><div class="eyebrow">Founder profile</div><h2 id="profileDisplayName">${p.name||'Keyona'}</h2><p class="founder-title">${p.title||'Founder of The Key Collective'}</p><blockquote>${p.mission||'Unlock the life you’re building, one intentional choice at a time.'}</blockquote><div class="founder-meta"><span>Personal Edition</span><span>OS v1.0</span><span>${new Date().getFullYear()} Blueprint</span></div></div><div class="life-orb" style="--score:${life}%"><strong>${life}</strong><small>Life score</small></div></section><div class="profile-metrics"><article class="card"><div class="mini">Goal momentum</div><div class="metric">${goalPct}%</div><div class="bar"><span style="width:${goalPct}%"></span></div></article><article class="card"><div class="mini">Wellness</div><div class="metric">${well}%</div><div class="bar"><span style="width:${well}%"></span></div></article><article class="card"><div class="mini">Financial goals</div><div class="metric">${financial}%</div><div class="bar"><span style="width:${financial}%"></span></div></article><article class="card"><div class="mini">Achievements</div><div class="metric">${wins}</div><p class="muted">Recorded wins</p></article></div><div class="profile-grid"><article class="card blueprint-card"><div class="section-title"><div><div class="eyebrow">My blueprint</div><h3>Direction before distraction</h3></div><span class="pill">Editable</span></div><label>Name<input id="profileName" value="${p.name||''}"></label><label>Founder title<input id="profileTitle" value="${p.title||''}"></label><label>Mission<textarea id="profileMission" rows="3">${p.mission||''}</textarea></label><label>Vision<textarea id="profileVision" rows="3">${p.vision||''}</textarea></label><label>Annual theme<input id="profileAnnualTheme" value="${p.annualTheme||''}"></label><label>Five-year vision<textarea id="profileFiveYear" rows="4">${p.fiveYearVision||''}</textarea></label><label>Legacy statement<textarea id="profileLegacy" rows="4">${p.legacy||''}</textarea></label><button id="saveProfile" class="btn">Save My Blueprint</button></article><article class="card"><div class="eyebrow">Core values</div><h3>The principles in the room</h3><div id="valueChips" class="value-chips">${(p.values||[]).map(v=>`<span>${v}</span>`).join('')}</div><label>Values, separated by commas<textarea id="profileValues" rows="4">${(p.values||[]).join(', ')}</textarea></label><button id="saveValues" class="btn secondary">Update values</button><div class="quick-actions"><button class="btn ghost" data-jump="goals">Goal Headquarters</button><button class="btn ghost" data-jump="progress">Growth Studio</button><button class="btn ghost" data-jump="premium">Design + Data</button></div></article><article class="card span-2 quick-info-card"><div class="section-title"><div><div class="eyebrow">Screenshot-ready</div><h3>My Quick Info</h3></div><span class="pill">Private · editable</span></div><div class="quick-info-grid">${[['birthday','Birthday'],['age','Age'],['height','Height'],['clothingSize','Clothing size'],['shoeSize','Shoe size'],['bloodType','Blood type'],['medications','Current medications'],['allergies','Allergies'],['emergencyContact','Emergency contact']].map(([k,l])=>`<label>${l}<input data-profile-quick="${k}" value="${p.quickInfo?.[k]||''}"></label>`).join('')}</div><button id="saveProfileQuick" class="btn">Save Quick Info</button></article><article class="card span-2"><div class="section-title"><div><div class="eyebrow">Achievement cabinet</div><h3>Evidence of momentum</h3></div><span class="pill">${wins} collected</span></div><div class="achievement-grid">${[x.journalEntries.length?['📖','Reflection started',`${x.journalEntries.length} entries`]:['📖','Reflection awaits','Your first entry'],x.goals.length?['🎯','Goals in motion',`${x.goals.length} active`]:['🎯','Vision ready','Add your first goal'],x.water>=8?['💧','Hydration complete','8 of 8 today']:['💧','Wellness building',`${x.water} of 8 water`],x.savingsGoals.length?['💎','Wealth intention',`${x.savingsGoals.length} savings goals`]:['💎','Financial canvas','Create a savings goal']].map(a=>`<div class="achievement"><span>${a[0]}</span><div><b>${a[1]}</b><small>${a[2]}</small></div></div>`).join('')}</div></article></div>`}
};


/* Executive Refinement Sprint 2 page experiences */
const esc=v=>String(v??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
const growthStats=x=>{const completed=x.goals.filter(g=>Number(g.progress)>=100).length;const goalXP=x.goals.reduce((n,g)=>n+Math.round(Number(g.progress||0)*2),0);const habitXP=x.journalEntries.length*25+x.water*5+Math.min(x.gymMinutes,120);const financeXP=x.savingsGoals.reduce((n,g)=>n+Math.round(Math.min(100,Number(g.current||0)/Math.max(1,Number(g.target||1))*100)),0);const winXP=(x.wins.length+(x.growth?.manualWins?.length||0))*75;const xp=Math.max(Number(x.growth?.xp||0),goalXP+habitXP+financeXP+winXP);const level=Math.floor(xp/500)+1;const names=['Builder','Creator','Leader','Architect','Visionary','Legacy'];return {xp,level,title:names[Math.min(names.length-1,Math.floor((level-1)/3))],next:500-(xp%500),completed};};

pages.business=function(){const x=s(),cached=x.pulseCache||{},allTopics=['U.S. News','Arizona + Phoenix','Payments + Fintech','AI + Technology','Markets + Economy','Business'],topics=x.pulsePreferences?.topics?.filter(t=>allTopics.includes(t))||allTopics;return `<div class="pagehead pulse-head"><div><div class="eyebrow">American executive intelligence</div><h1>Pulse</h1><p class="sub">Curated U.S. news in English, with dedicated Arizona, payments, AI, markets, and business coverage.</p></div><div class="pulse-actions"><span id="pulseUpdated" class="pill">${cached.updatedAt?`Updated ${new Date(cached.updatedAt).toLocaleString('en-US')}`:'Ready to refresh'}</span><button id="pulseSettings" class="btn secondary">Customize</button><button id="refreshPulse" class="btn">Refresh briefing</button></div></div><section id="pulseHero" class="card pulse-hero american-pulse"><div><div class="eyebrow">Executive summary · United States</div><h2 id="pulseHeroTitle">Your American briefing desk is ready.</h2><p id="pulseHeroText">Refresh for current English-language headlines selected around your priorities.</p></div><div id="pulseState" class="pulse-state"><span class="pulse-orb"></span><b>English · U.S.</b><small>Filtered by language and source country</small></div></section><section id="pulsePreferences" class="card pulse-preferences" hidden><div class="section-title"><div><div class="eyebrow">Topic preferences</div><h3>Choose your briefing channels</h3></div><button id="closePulseSettings" class="btn ghost">Done</button></div><div class="topic-toggle-grid">${allTopics.map(t=>`<label class="topic-toggle"><input type="checkbox" data-pulse-pref="${esc(t)}" ${topics.includes(t)?'checked':''}><span>${esc(t)}</span></label>`).join('')}</div><p class="muted">World news stays off unless you intentionally add it in a future release.</p></section><div id="pulseSummary" class="pulse-summary"></div><div id="pulseTopics" class="pulse-topic-grid">${topics.map(t=>`<article class="card pulse-topic" data-pulse-topic="${esc(t)}"><div class="section-title"><div><div class="mini">U.S. English channel</div><h3>${esc(t)}</h3></div><span class="pill">Waiting</span></div><div class="pulse-skeleton">${'<i></i>'.repeat(3)}</div></article>`).join('')}</div><article class="card pulse-connection"><div><div class="eyebrow">Source standard</div><h3>English-first, America-focused.</h3><p>Pulse requests English reporting from U.S. sources, then performs an additional language check before displaying a headline. The last successful briefing remains cached for offline reading.</p></div><span class="pill">No private keys in GitHub</span></article>`};

pages.progress=function(){const x=s(),g=growthStats(x),levelPct=Math.round((g.xp%500)/5),wins=[...(x.growth?.manualWins||[]),...x.wins],streak=Number(x.growth?.streak||0),badges=[['🔑','First Key',x.goals.length>0,'Create your first goal'],['🔥','Momentum',streak>=3,'Complete 3 daily check-ins'],['💧','Well Kept',x.water>=8,'Reach 8 glasses in a day'],['📖','Inner Voice',x.journalEntries.length>=5,'Save 5 reflections'],['💎','Wealth Builder',x.savingsGoals.length>0,'Create a savings goal'],['🏆','Finisher',g.completed>0,'Complete a 25 Hard goal']];return `<div class="pagehead growth-head"><div><div class="eyebrow">Motivation, not just measurement</div><h1>Growth Studio</h1><p class="sub">Every intentional action becomes evidence that your life is moving.</p></div><button id="dailyCheckIn" class="btn">Claim today’s XP</button></div><section class="card level-hero"><div><div class="eyebrow">Level ${g.level}</div><h2>${g.title}</h2><p>${g.next} XP until your next level. Small choices count here.</p><div class="level-bar"><span style="width:${levelPct}%"></span></div></div><div class="xp-orb"><strong>${g.xp.toLocaleString()}</strong><small>Lifetime XP</small></div></section><div class="growth-story-grid"><article class="card"><div class="mini">Current streak</div><div class="metric">${streak} days</div><p>${streak?'You are building proof through repetition.':'Today can become day one.'}</p></article><article class="card"><div class="mini">Goals completed</div><div class="metric">${g.completed}</div><p>${g.completed?'Finished goals belong in the cabinet.':'The future is waiting for its first milestone.'}</p></article><article class="card"><div class="mini">Reflections saved</div><div class="metric">${x.journalEntries.length}</div><p>${x.journalEntries.length?'Your story is becoming visible.':'Your story begins with today’s first reflection.'}</p></article><article class="card"><div class="mini">Recorded wins</div><div class="metric">${wins.length}</div><p>${wins.length?'Momentum has receipts.':'Name one thing you did well today.'}</p></article></div><div class="grid g2"><article class="card"><div class="section-title"><div><div class="eyebrow">Today’s win</div><h3>Make progress memorable</h3></div><span class="pill">+75 XP</span></div><textarea id="newWinText" rows="3" placeholder="What deserves to be celebrated today?"></textarea><button id="addGrowthWin" class="btn">Add to celebration timeline</button><div id="wins" class="celebration-list"></div></article><article class="card"><div class="section-title"><div><div class="eyebrow">Achievement cabinet</div><h3>Unlocked by living the system</h3></div><span class="pill">${badges.filter(b=>b[2]).length}/${badges.length}</span></div><div class="badge-grid">${badges.map(b=>`<div class="growth-badge ${b[2]?'unlocked':'locked'}"><span>${b[0]}</span><b>${b[1]}</b><small>${b[2]?'Unlocked':b[3]}</small></div>`).join('')}</div></article><article class="card"><h3>Milestone Timeline</h3><div id="milestoneTimeline"></div></article><article class="card"><h3>28-Day Activity</h3><div id="activityHeatmap" class="heatmap"></div><p class="muted">Consistency creates the quiet confidence that motivation cannot.</p></article><article class="card span-2"><div class="section-title"><h3>Category Momentum</h3><span class="pill">Connected across your OS</span></div><canvas id="progressCanvas" height="260"></canvas></article></div>`};

pages.sanctuary=function(){const x=s(),rituals=[['morning','☀️','Morning Reset','Open the home gently and choose the day.',['Make the bed','Open curtains','Kitchen refresh','Review today’s Top Three']],['evening','🌙','Evening Reset','Close loops so tomorrow begins lighter.',['Kitchen close','Ten-minute tidy','Prepare tomorrow','Set devices to rest']],['weekly','🕯️','Weekly Reset','Restore order and make room for the next week.',['Laundry reset','Refresh groceries','Review calendar','Choose weekly intention']],['monthly','🌿','Monthly Reset','Notice patterns before they become pressure.',['Review finances','Declutter one zone','Archive memories','Set monthly focus']],['quarterly','🔑','Quarterly Review','Honor progress and realign the blueprint.',['Review goals','Celebrate wins','Adjust priorities','Plan next quarter']],['annual','✨','Annual Reflection','Close the year with evidence, grace, and vision.',['Review the year','Name the lessons','Choose annual theme','Write future-self letter']],['vision','🦋','Vision Reset','Return to the life you are intentionally building.',['Read mission','Read five-year vision','Refresh vision board','Choose next brave move']]];return `<div class="pagehead sanctuary-head"><div><div class="eyebrow">Ritual center</div><h1>Sanctuary</h1><p class="sub">A calm home for resets, reflection, and the rhythms that hold everything else.</p></div><span class="pill">Private · local</span></div><section class="card sanctuary-hero"><div><div class="eyebrow">The art of returning</div><h2>Your home does not need perfection. It needs rhythm.</h2><p>Choose the reset that meets the season you are in.</p></div><span class="sanctuary-mark">❧</span></section><div class="ritual-grid">${rituals.map(([id,icon,title,copy,steps])=>`<article class="card ritual-card"><span class="ritual-icon">${icon}</span><div><div class="mini">${id==='vision'?'Anytime':id}</div><h3>${title}</h3><p>${copy}</p></div><div class="ritual-checks">${steps.map((step,i)=>`<label><input type="checkbox" data-ritual="${id}" data-step="${i}" ${x.sanctuary?.completed?.[id]?.[i]?'checked':''}><span>${step}</span></label>`).join('')}</div><textarea data-ritual-note="${id}" rows="2" placeholder="Add a private note…">${esc(x.sanctuary?.notes?.[id]||'')}</textarea></article>`).join('')}</div>`};

pages.profile=function(){const x=s(),p=x.profile||{},g=growthStats(x),goalPct=x.goals.length?Math.round(x.goals.reduce((a,g)=>a+Number(g.progress||0),0)/x.goals.length):0,well=Math.min(100,Math.round(x.water/8*55+Math.min(x.gymMinutes,60)/60*45)),savings=x.savingsGoals.reduce((a,g)=>a+Number(g.current||0),0),target=x.savingsGoals.reduce((a,g)=>a+Number(g.target||0),0),financial=target?Math.min(100,Math.round(savings/target*100)):0,life=Math.round((goalPct+well+financial+Math.min(100,x.journalEntries.length*5))/4);return `<div class="pagehead profile-head"><div><div class="eyebrow">Founder identity suite</div><h1>My Profile</h1><p class="sub">The person, purpose, and priorities behind The Key Collective.</p></div><button class="btn ghost" data-jump="premium">Open Design + Data</button></div><section class="founder-card card founder-experience"><img src="profile.jpg" alt="Founder portrait"><div><div class="eyebrow">Founder of The Key Collective</div><h2>${esc(p.name||'Keyona')}</h2><p class="founder-title">${esc(p.title||'Founder of The Key Collective')}</p><blockquote>${esc(p.mission||'Unlock the life you’re building, one intentional choice at a time.')}</blockquote><div class="founder-meta"><span>${esc(p.annualTheme||'Becoming')}</span><span>${g.title} · Level ${g.level}</span><span>Personal Edition v10.0</span></div></div><div class="life-orb" style="--score:${life}%"><strong>${life}</strong><small>Life score</small></div></section><div class="profile-focus-grid"><article class="card"><div class="mini">Today’s intention</div><textarea id="profileTodayIntent" rows="3" placeholder="How do you want to move through today?">${esc(p.todayIntent||'')}</textarea></article><article class="card"><div class="mini">Current focus</div><textarea id="profileCurrentFocus" rows="3" placeholder="What deserves your best attention now?">${esc(p.currentFocus||'')}</textarea></article><article class="card"><div class="mini">Quarterly priorities</div><textarea id="profileQuarterly" rows="3" placeholder="Three priorities, separated by commas">${esc((p.quarterlyPriorities||[]).join(', '))}</textarea></article><article class="card identity-stat"><div class="mini">Identity level</div><div class="metric">${g.title}</div><p>${g.xp.toLocaleString()} lifetime XP</p></article></div><div class="profile-grid"><article class="card blueprint-card"><div class="section-title"><div><div class="eyebrow">My blueprint</div><h3>Direction before distraction</h3></div><span class="pill">Editable</span></div><label>Name<input id="profileName" value="${esc(p.name||'')}"></label><label>Founder title<input id="profileTitle" value="${esc(p.title||'')}"></label><label>Mission<textarea id="profileMission" rows="3">${esc(p.mission||'')}</textarea></label><label>Vision<textarea id="profileVision" rows="3">${esc(p.vision||'')}</textarea></label><label>Annual theme<input id="profileAnnualTheme" value="${esc(p.annualTheme||'')}"></label><label>Five-year vision<textarea id="profileFiveYear" rows="4">${esc(p.fiveYearVision||'')}</textarea></label><label>Legacy statement<textarea id="profileLegacy" rows="4">${esc(p.legacy||'')}</textarea></label><button id="saveProfile" class="btn">Save Founder Blueprint</button></article><article class="card"><div class="eyebrow">Core values</div><h3>The principles in the room</h3><div id="valueChips" class="value-chips">${(p.values||[]).map(v=>`<span>${esc(v)}</span>`).join('')}</div><label>Values, separated by commas<textarea id="profileValues" rows="4">${esc((p.values||[]).join(', '))}</textarea></label><button id="saveValues" class="btn secondary">Update values</button><div class="quick-actions"><button class="btn ghost" data-jump="progress">Growth Studio</button><button class="btn ghost" data-jump="sanctuary">Sanctuary</button><button class="btn ghost" data-jump="premium">Design + Data</button></div><div class="profile-data"><b>Your private OS</b><small>${x.goals.length} goals · ${x.journalEntries.length} reflections · ${x.bills.length} bills · ${Object.keys(x.calendar).length} planned days</small></div></article><article class="card span-2 quick-info-card"><div class="section-title"><div><div class="eyebrow">Screenshot-ready</div><h3>My Quick Info</h3></div><span class="pill">Private · editable</span></div><div class="quick-info-grid">${[['birthday','Birthday'],['age','Age'],['height','Height'],['clothingSize','Clothing size'],['shoeSize','Shoe size'],['bloodType','Blood type'],['medications','Current medications'],['allergies','Allergies'],['emergencyContact','Emergency contact']].map(([k,l])=>`<label>${l}<input data-profile-quick="${k}" value="${p.quickInfo?.[k]||''}"></label>`).join('')}</div><button id="saveProfileQuick" class="btn">Save Quick Info</button></article><article class="card span-2"><div class="section-title"><div><div class="eyebrow">Achievement cabinet</div><h3>Evidence of becoming</h3></div><span class="pill">Level ${g.level}</span></div><div class="achievement-grid">${[[x.journalEntries.length?'📖':'◇','Reflection practice',x.journalEntries.length?`${x.journalEntries.length} entries`:'Your story begins today'],[x.goals.length?'🎯':'◇','Vision in motion',x.goals.length?`${x.goals.length} active goals`:'The future awaits a milestone'],[x.water>=8?'💧':'◇','Wellness stewardship',x.water>=8?'Hydration complete':`${x.water} of 8 water`],[x.savingsGoals.length?'💎':'◇','Wealth intention',x.savingsGoals.length?`${x.savingsGoals.length} savings goals`:'Create your first savings goal']].map(a=>`<div class="achievement"><span>${a[0]}</span><div><b>${a[1]}</b><small>${a[2]}</small></div></div>`).join('')}</div></article></div>`};

// Sprint 3 · Living Intelligence page upgrades
pages.goals=function(){const x=s(),done=x.goals.filter(g=>Number(g.progress)>=100).length;return `<div class="pagehead"><div><div class="eyebrow">The annual becoming list</div><h1>25 Hard</h1><p class="sub">Twenty-five milestones. One intentional life. Progress should feel beautiful enough to revisit.</p></div><span id="hardCount" class="pill">${done}/25 complete</span></div><section class="card hard-hero"><div><div class="eyebrow">Your next brave move</div><h2>Choose the milestone that changes the story.</h2></div><div class="hard-add"><input id="hardGoalName" placeholder="Name a meaningful milestone"><select id="hardGoalCategory"><option>Personal</option><option>Financial</option><option>Career</option><option>Wellness</option><option>Family</option><option>Adventure</option></select><button id="addHardGoal" class="btn">Add milestone</button></div></section><div id="hardGrid" class="hard-grid"></div>`};

pages.career=function(){const x=s(),completed=Number(x.academy?.completed||0);return `<div class="pagehead"><div><div class="eyebrow">Interactive payments mastery</div><h1>Payments Academy</h1><p class="sub">Learn the flow, test the knowledge, earn the proof.</p></div><span class="pill">${completed} knowledge checks</span></div><section class="card academy-hero"><div><div class="eyebrow">Learning path</div><h2>Authorization → Clearing → Settlement</h2><p>Follow the money and the messages. Each completed knowledge check earns 100 XP.</p></div><div class="academy-flow"><span>Cardholder</span><i>→</i><span>Merchant</span><i>→</i><span>Acquirer</span><i>→</i><span>Network</span><i>→</i><span>Issuer</span></div></section><div class="grid g2"><article class="card quiz-card"><div class="eyebrow">Knowledge check</div><h3 id="quizQuestion"></h3><div id="quizOptions" class="quiz-options"></div></article><article class="card"><div class="eyebrow">Private case notes</div><h3>Capture what becomes clear</h3><textarea id="academyNote" rows="8" placeholder="Document a concept, case, or question…"></textarea><button id="saveAcademyNote" class="btn">Save case note</button><p class="muted">${x.careerNotes.length} saved note${x.careerNotes.length===1?'':'s'}</p></article></div>`};

pages.wellness=function(){const x=s(),w=x.wellness||{},score=Math.round((Math.min(8,x.water)/8*30+Math.min(60,x.gymMinutes)/60*25+Math.min(9,Number(w.sleep||0))/9*25+Number(w.recovery||0)/100*20));return `<div class="pagehead"><div><div class="eyebrow">Whole-person stewardship</div><h1>Wellness Studio</h1><p class="sub">Track energy, restoration, movement, and the small rituals that hold you.</p></div><span class="pill">Wellness score ${score}</span></div><section class="card wellness-score"><div class="wellness-ring" style="--p:${score}%"><strong>${score}</strong><small>Today</small></div><div><h2>Your body is part of the strategy.</h2><p>Notice the trend without turning your life into a spreadsheet with feelings.</p></div></section><div class="wellness-grid"><article class="card"><div class="mini">Hydration</div><div class="metric">${x.water}/8</div><div class="bar"><span style="width:${Math.min(100,x.water/8*100)}%"></span></div><div class="button-row"><button class="btn ghost" data-water="-1">−</button><button class="btn" data-water="1">Add water</button></div></article><article class="card"><label>Movement minutes<input id="wellMinutes" type="number" min="0" value="${x.gymMinutes}"></label><label>Sleep hours<input id="wellSleep" type="number" min="0" max="14" step="0.5" value="${Number(w.sleep||0)}"></label></article><article class="card"><label>Mood<select id="wellMood">${['Radiant','Steady','Tender','Tired','Stretched'].map(v=>`<option ${w.mood===v?'selected':''}>${v}</option>`).join('')}</select></label><label>Recovery score<input id="wellRecovery" type="range" min="0" max="100" value="${Number(w.recovery||70)}"></label><button id="saveWellness" class="btn">Save wellness check-in</button></article></div>`};

pages.money=function(){const x=s(),income=Number(x.monthlyIncome||0),spend=Number(x.financial?.monthlySpending||0),bills=x.bills.reduce((a,b)=>a+Number(b.amount||0),0),monthlyNet=income-spend-bills,months=[1,3,6,12];return `<div class="pagehead"><div><div class="eyebrow">Financial intelligence</div><h1>Financial Studio</h1><p class="sub">Turn today’s numbers into a calmer view of what comes next.</p></div><span class="pill">Forecast ${monthlyNet>=0?'positive':'attention needed'}</span></div><section class="card forecast-hero"><div><div class="eyebrow">Projected monthly margin</div><div class="metric">${money(monthlyNet)}</div><p>Income minus planned spending and listed bills.</p></div><div class="forecast-strip">${months.map(m=>`<div><small>${m} month${m>1?'s':''}</small><b>${money(monthlyNet*m)}</b></div>`).join('')}</div></section><div class="grid g2"><article class="card"><h3>Forecast assumptions</h3><label>Monthly income<input id="forecastIncome" type="number" value="${income}"></label><label>Monthly variable spending<input id="forecastSpending" type="number" value="${spend}"></label><button id="saveForecast" class="btn">Update forecast</button></article><article class="card"><div class="eyebrow">Executive insight</div><h3>${monthlyNet>0?'Your current plan creates room.':'Your current plan needs a decision.'}</h3><p>${monthlyNet>0?`At this pace, twelve months could create approximately ${money(monthlyNet*12)} before unplanned expenses.`:`Listed commitments exceed current planned income by ${money(Math.abs(monthlyNet))} each month.`}</p><div class="metric-row"><span><b>${money(Number(x.checking)+Number(x.savings))}</b><small>Available cash</small></span><span><b>${money(bills)}</b><small>Listed bills</small></span></div></article></div>`};

pages.journal=function(){const x=s();return `<div class="pagehead"><div><div class="eyebrow">Searchable private reflection</div><h1>Reflection Garden</h1><p class="sub">A living archive of what you noticed, learned, and became.</p></div><span class="pill">${x.journalEntries.length} reflections</span></div><div class="grid g2"><article class="card reflection-compose"><div class="eyebrow">Today’s reflection</div><h3>What did today reveal?</h3><select id="s3Mood"><option>Reflective</option><option>Grateful</option><option>Hopeful</option><option>Tender</option><option>Determined</option></select><textarea id="s3Reflection" rows="10" placeholder="Write without editing yourself…"></textarea><button id="saveSprint3Reflection" class="btn">Save reflection</button></article><article class="card"><div class="section-title"><div><div class="eyebrow">Your archive</div><h3>Find the thread</h3></div></div><input id="journalSearch" type="search" placeholder="Search reflections, prompts, or themes"><select id="journalMoodFilter"><option value="">All moods</option><option>Reflective</option><option>Grateful</option><option>Hopeful</option><option>Tender</option><option>Determined</option></select><div id="journalLibrary" class="journal-library"></div></article></div>`};
